const rows = $input.all();
if (rows.length === 0) {
  return [{ json: { hoursSinceCheckIn: 9999, lastCheckIn: 'never', status: 'CRITICAL' } }];
}
const configRow = rows[0];
const lastRow = rows[rows.length - 1];
const lastCheckIn = new Date(lastRow.json.timestamp);
const now = new Date();
const hoursDiff = (now - lastCheckIn) / (1000 * 60 * 60);
const threshold = configRow.json.threshold_hours ? parseInt(configRow.json.threshold_hours) : 24;

let status = 'OK';
if (hoursDiff > threshold * 2) {
  status = 'CRITICAL';
} else if (hoursDiff > threshold) {
  status = 'WARNING';
}

return [{
  json: {
    hoursSinceCheckIn: Math.round(hoursDiff * 10) / 10,
    lastCheckIn: lastCheckIn.toISOString(),
    thresholdHours: threshold,
    status,
    founderName: configRow.json.founder_name || 'Founder',
    founderEmail: configRow.json.founder_email || '',
    emergencyContact1: configRow.json.emergency_contact_1 || '',
    emergencyContact2: configRow.json.emergency_contact_2 || '',
    emergencyMessage: configRow.json.emergency_message || 'This is an automated message. I have not checked in to my Dead Mans Switch in over ' + Math.round(hoursDiff) + ' hours. Please check on me.'
  }
}];

